:root {
  --bg-card: #1e1208;
  --bg-header: #2e1a0e;
  --bg-body: #fdf6ee;
  --bg-stat: #f4e8d6;
  --bg-tag: #ffe8c4;
  --accent-primary: #b85c1a;
  --accent-secondary: #e8935a;
  --bar-filled: #b85c1a;
  --bar-half: #e8c49a;
  --bar-empty: #e0d0be;
  --text-header-title: #f5dfc0;
  --text-header-date: #c49a6c;
  --text-bean-name: #2e1a0e;
  --text-bean-origin: #7a5230;
  --text-stat-value: #b85c1a;
  --text-stat-label: #9a7252;
  --text-flavor-label: #7a5230;
  --text-tag: #7a3c10;
  --text-rating-label: #7a5230;
  --text-rating-score: #b85c1a;
  --badge-bg: #b85c1a;
  --badge-text: #fff7ee;
  --border-color: #e0c8a8;
  --radius-card: 14px;
  --radius-stat: 8px;
  --radius-tag: 20px;
  --radius-bar: 4px;
}

.journal {
  width: 480px;
  border-radius: var(--radius-card);
  overflow: hidden;
  border: 2px solid var(--bg-card);
  margin: 0 auto;
}

.journal-header {
  background-color: var(--bg-header);
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 18px;
}

.brew-icon {
  font-size: 28px;
  line-height: 1;
}

.header-text {
  display: flex;
  flex-direction: column;
  gap: 2px;
  flex: 1;
}

.journal-title {
  font-size: 18px;
  font-weight: 700;
  color: var(--text-header-title);
  line-height: 1.2;
}

.journal-date {
  font-size: 12px;
  font-weight: 400;
  color: var(--text-header-date);
}

.brew-badge {
  background-color: var(--badge-bg);
  color: var(--badge-text);
  font-size: 11px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: var(--radius-tag);
}

.journal-body {
  background-color: var(--bg-body);
  padding: 16px 18px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.bean-info {
  display: flex;
  flex-direction: column;
  gap: 3px;
  border-left: 3px solid var(--accent-primary);
  padding-left: 10px;
}

.bean-name {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-bean-name);
  margin: 0;
}

.bean-origin {
  font-size: 12px;
  font-weight: 400;
  color: var(--text-bean-origin);
  margin: 0;
}

.stats-row {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.stat {
  background-color: var(--bg-stat);
  border-radius: var(--radius-stat);
  padding: 10px 6px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
}

.stat-value {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-stat-value);
  line-height: 1;
}

.stat-label {
  font-size: 11px;
  font-weight: 500;
  color: var(--text-stat-label);
}

.flavor-section {
  display: flex;
  flex-direction: column;
  gap: 7px;
}

.flavor-label {
  font-size: 11px;
  font-weight: 600;
  color: var(--text-flavor-label);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.flavor-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.tag {
  background-color: var(--bg-tag);
  color: var(--text-tag);
  font-size: 12px;
  font-weight: 500;
  padding: 4px 10px;
  border-radius: var(--radius-tag);
  border: 1px solid var(--border-color);
}

.rating-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding-top: 2px;
  border-top: 1px solid var(--border-color);
}

.rating-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-rating-label);
  white-space: nowrap;
}

.rating-bars {
  display: flex;
  gap: 4px;
  flex: 1;
  align-items: center;
}

.bar {
  height: 10px;
  flex: 1;
  border-radius: var(--radius-bar);
  background-color: var(--bar-empty);
}

.bar.filled {
  background-color: var(--bar-filled);
}

.bar.half {
  background-color: var(--bar-half);
}

.rating-score {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-rating-score);
  white-space: nowrap;
}
